        local has3 = true
        local has4 = true
        local ch3 = d_0xlIII1I:sub(i_0xl1IlIl+2,i_0xl1IlIl+2)
        if ch3 == "=" then has3 = false else c_0xllII1l = b64_0xllIl1l[ch3] or 0 end
        local ch4 = d_0xlIII1I:sub(i_0xl1IlIl+3,i_0xl1IlIl+3)
        if ch4 == "=" then has4 = false else c_0xlIIlIl = b64_0xllIl1l[ch4] or 0 end
