        local b_0xllIl1I = math.floor(b_0xlll1ll / (2^16)) % (2^8)
        local b_0xll1l1l = math.floor(b_0xlll1ll / (2^8)) % (2^8)
        local b_0x11I1ll = b_0xlll1ll % (2^8)
        table.insert(r_0x1lIlll, string.char(b_0xllIl1I))
        if has3 then table.insert(r_0x1lIlll, string.char(b_0xll1l1l)) end
        if has4 then table.insert(r_0x1lIlll, string.char(b_0x11I1ll)) end
