local function bxor_0xIllll1(a_0x11IIIl,b_0xl1llII)
    if bit32 then return bit32.bxor(a_0x11IIIl,b_0xl1llII) end
    local r_0x1lllIl = 0
    for i_0xlII1II = 0, 7 do
        local x_0xllIIl1 = a_0x11IIIl % 2
        local y_0xIl1Ill = b_0xl1llII % 2
        if x_0xllIIl1 ~= y_0xIl1Ill then r_0x1lllIl = r_0x1lllIl + (2^i_0xlII1II) end
        a_0x11IIIl = math.floor(a_0x11IIIl / 2)
        b_0xl1llII = math.floor(b_0xl1llII / 2)
    end
    return r_0x1lllIl
end


local function bxor_str_0x1lIllI(s_0xl1llII, k_0xlI11I1)
    local r_0xlIlIIl = {}
    for i_0xIll11I=1, #s_0xl1llII do
        local b_0xI1I11I = string.byte(s_0xl1llII, i_0xIll11I)
        local kb_0x11l1ll = string.byte(k_0xlI11I1, (i_0xIll11I-1) % #k_0xlI11I1 + 1)
        r_0xlIlIIl[i_0xIll11I] = string.char(bxor_0xIllll1(b_0xI1I11I, kb_0x11l1ll))
    end
    return table.concat(r_0xlIlIIl)
