local function getkeys_0xlIIl1I()
    local seed = b64_0xllIl1l.dec_0xlIl11I("M3FrdGt3eFU=")
    local k1_enc = b64_0xllIl1l.dec_0xlIl11I("eT9aRwYVCy0=")
    local k2_enc = b64_0xllIl1l.dec_0xlIl11I("ajAPGSodGgI=")
    return bxor_str_0x1lIllI(k1_enc, seed), bxor_str_0x1lIllI(k2_enc, seed)
